%[text] # 배열 행렬 만들기
%[text] 이름: 김정수
%[text] 
m=[1 4 2 5] %row vector %[output:36d45267]
v=[1; 4; 2; 5] %column vector %[output:569991be]
M=magic(3) %[output:18ab6203]
[n,r]=size(M) %[output:81a00e73] %[output:83ad030d]
nn= size(M,2) %[output:2ee6e7a3]
ln=length(M) %[output:67d1c236]
N=M' %[output:790ad0d9]
K=numel(M) %[output:3bc2b288]
%%
%[text] ## 그래프
v %[output:7535ce15]
a=plot(v,'r--o','MarkerFaceColor','r') %[output:56204708] %[output:92470af1]
grid on %[output:92470af1]
a.LineWidth=5 %[output:8c2476c8] %[output:92470af1]
xlabel('$x$','Interpreter','latex');ylabel('y') %[output:92470af1]
%%
stem(v,'r','filled'); %[output:2192c378]
grid on;xlabel('value'),ylabel('measured') %[output:2192c378]
bar(v, 'facecolor','g');legend('income') %[output:4e53f62f]
%[text]  
%%
%[text] ## 복소수 배열/complex arrays
a=2i+1 %[output:9d0d8e8d]
aR=real(a), aImag=imag(a) %[output:8027bc3c] %[output:0cd35f3d]
b=[1 2i 1-i -1] %[output:3619f614]
b1=b(1), b2=b(2) %[output:0253da17] %[output:44c304e9]
b3=b.^2 %[output:16c97ca6]
%%
%[text] # array addressing
H=10:-2:0 %[output:2032ea22]
H(1:2),H(end-1:end),H(1:2:end) %[output:80967c60] %[output:6dfb2026] %[output:61b16191]
K=H([2 5 4 3 1 6]) %[output:9b7a026d]
L=magic(5) %[output:78da94c6]
B=L(end,:) %[output:16b5222d]
A=L(:,3) %[output:77ea8f90]
C=L(4:5,[2 4]) %[output:599f7278]
v,v(7)=5 %[output:2b375a35] %[output:477630d8]
%%
%[text] ### 배열을 만드는 또 다른 방법
q=(3:4:9)+2 %[output:5a87abd5]
F=linspace(0,10, 3) %[output:48122b51]
G=logspace(0, 4, 5) %[output:70713b4d]
O=0:4,10.^O %[output:58a0e08b] %[output:3e9849fa]
%%
%[text] ### 특별한 행렬
T=zeros(4)-pi %[output:920baea0]
U=ones(4,6)*3 %[output:55464610]
W=magic(4) %[output:11fb203a]
dm=diag(diag(W)) %[output:3670a78e]
E=eye(4)*3 %[output:4322176a]
E2=E.^2 %[output:7c48187d]
%[text] 

